import ast, os, sys, json

ROOT = "/home/polaris/wt/phase3a"

# Priority buckets (higher weight = more important to a reviewer)
# Each entry: (glob-prefix relative to src, weight, label)
PRIORITY = [
    ("polaris_graph/api/", 100, "graph-api-route"),
    ("polaris_v6/api/", 95, "v6-api-route"),
    ("polaris_v6/schemas/", 90, "v6-schema-contract"),
    ("schemas/", 88, "top-schema"),
    ("polaris_graph/evidence_contract/", 85, "evidence-contract"),
    ("polaris_graph/contracts_v3.py", 84, "contracts-v3"),
    ("polaris_graph/v30_contract_synthesizer.py", 80, "contract-synth"),
    ("polaris_graph/wiki/mesh/api/", 70, "mesh-api"),
]

# main entrypoints get a boost
ENTRYPOINTS = {"polaris_v6/api/app.py"}


def rel(p):
    return os.path.relpath(p, os.path.join(ROOT, "src"))


def is_public(name):
    return not name.startswith("_")


def analyze(path):
    relp = rel(path)
    weight = None
    label = None
    for prefix, w, lab in PRIORITY:
        if relp == prefix or relp.startswith(prefix):
            weight, label = w, lab
            break
    if weight is None:
        return []
    if relp in ENTRYPOINTS:
        weight += 5
    try:
        src = open(path, encoding="utf-8").read()
        tree = ast.parse(src)
    except Exception:
        return []
    results = []
    # module-level docstring
    mod_name = os.path.basename(path)
    if ast.get_docstring(tree) is None and mod_name != "__init__.py":
        results.append((weight + 3, relp, f"<module>", "module", label))

    for node in tree.body:
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if is_public(node.name) and ast.get_docstring(node) is None:
                # route handlers / decorated functions get a boost
                boost = 2 if node.decorator_list else 0
                results.append((weight + boost, relp, node.name, "function", label))
        elif isinstance(node, ast.ClassDef):
            if is_public(node.name) and ast.get_docstring(node) is None:
                results.append((weight + 2, relp, node.name, "class", label))
            # public methods of public classes
            for sub in node.body:
                if isinstance(sub, (ast.FunctionDef, ast.AsyncFunctionDef)):
                    if is_public(sub.name) and ast.get_docstring(sub) is None:
                        # dunder skip except a few
                        if sub.name.startswith("__"):
                            continue
                        results.append((weight - 1, relp, f"{node.name}.{sub.name}", "method", label))
    return results


all_targets = []
for prefix, w, lab in PRIORITY:
    base = os.path.join(ROOT, "src", prefix)
    if os.path.isfile(base):
        all_targets.extend(analyze(base))
    elif os.path.isdir(base):
        for dp, dn, fn in os.walk(base):
            for f in fn:
                if f.endswith(".py"):
                    all_targets.extend(analyze(os.path.join(dp, f)))

# dedupe
seen = set()
uniq = []
for t in all_targets:
    key = (t[1], t[2])
    if key in seen:
        continue
    seen.add(key)
    uniq.append(t)

uniq.sort(key=lambda x: (-x[0], x[1], x[2]))

print("TOTAL_MISSING_IN_PRIORITY:", len(uniq))
# counts by label
from collections import Counter
c = Counter(t[4] for t in uniq)
print("BY_LABEL:", dict(c))
ck = Counter(t[3] for t in uniq)
print("BY_KIND:", dict(ck))

out = []
for w, relp, sym, kind, lab in uniq:
    out.append({"weight": w, "file": "src/" + relp, "symbol": sym, "kind": kind, "area": lab})

json.dump(out, open("/tmp/claude-1000/-home-polaris-polaris-project/21e87760-8436-4090-870d-99ef2121882e/scratchpad/targets.json", "w"), indent=1)
print("---TOP 60---")
for r in out[:60]:
    print(f"{r['weight']:>3} [{r['area']:<18}] {r['file']}:{r['symbol']} ({r['kind']})")
